const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
const mode = isMobile ? 'redirect' : 'auto';
await session.start({ presentationMode: mode }, createOrder())

popup_with_fallback.code:
try {
  await session.start({ presentationMode: 'popup' }, createOrder());
} catch (error) {
  if (error.code === 'ERR_DEV_UNABLE_TO_OPEN_POPUP') {
    await session.start({ presentationMode: 'modal' }, createOrder());
  }
}

